// Data loading

interface ScrapedSpot {
  id: string;
  url: string;
  name: string;
  description: string | null;
  address: string | null;
  coordinates: { lat: number; lng: number } | null;
  language: string;
  source_url: string;
  last_scraped_at: string;
}

interface MunicipalityBlock {
  municipality: {
    code: string;
    name: string;
    prefecture_code: string;
    prefecture_name: string;
  };
  spots: ScrapedSpot[];
}

interface WikidataAttraction {
  qid: string;
  wikidata_url: string;
  name_ja: string | null;
  name_en: string | null;
  name_zh: string | null;
  name_ko: string | null;
  description_en: string | null;
  coordinates: { lat: number; lng: number } | null;
  prefecture_code: string;
  admin_code: string | null;
  admin_name: string | null;
  // Iter 28: the v2 SPARQL fetcher records the matched
  // Wikidata type QID(s) per item (Q34038=waterfall / Q44613=temple /
  // Q23413=castle / etc.). v1 datasets may not have this field; treat as
  // optional. Used to expose a human-readable `kind` field downstream.
  types?: string[];
  // Iter 54: P1435 (heritage designation) values from
  // Wikidata. Populated by the heritage-anchor fetcher
  // (fetch_wikidata_p1435.ts). Used as a prominence signal — items with a
  // national/international heritage designation are higher-confidence
  // tourist destinations.
  heritage_designations?: string[];
  // "v2" | "p1435" | "direct_p31" | combinations like "p1435+v2"
  source_anchor?: string;
  // Iter 58: OSM-derived structured fields, joined to
  // Wikidata via the OSM `wikidata=Q*****` tag. Populated by
  // scrapers/merge_osm_tags_into_master.ts and supplemented at runtime
  // for prefecture files where the field hasn't been embedded.
  // Constraint-encodable for downstream Solver / Product 2.
  opening_hours?: string;
  wheelchair?: string;
  tactile_paving?: string;
  phone?: string;
  website?: string;
  email?: string;
  cuisine?: string;
  fee?: string;
  internet_access?: string;
  smoking?: string;
  osm_ids?: string[];
  osm_tags_merged_at?: string;
  // Iter62: Wikipedia category-derived kind_tags (giyofu / sand_dune /
  // mining_heritage / preservation_district / etc.). Populated by
  // scrapers/merge_wikipedia_kinds_into_master.ts. Used by wikidataKinds()
  // to expand the kinds[] field with semantic tags from public-source
  // ontology bridge (Wikipedia categories CC BY-SA).
  wikipedia_kind_tags?: string[];
  wikipedia_kind_tags_merged_at?: string;
  // Wikidata short description in Japanese (populated by
  // scripts/inject_wikidata_descriptions.py from wbgetentities backfill).
  description_ja?: string;
  // Mapped Wikipedia article titles (populated alongside description_ja).
  // Keys: 'en' / 'ja'. Used by future enrichment passes for Wikipedia
  // summary / abstract fetches.
  wikipedia_titles?: { en?: string; ja?: string };
  // Pre-computed nearest railway station and walk-minute estimate, populated
  // by scripts/inject_nearest_transit.py from data/_state/railway_stations.json.
  // Constraint-encodable Solver input (research_0504 Phase A).
  nearest_transit?: {
    station_qid: string;
    station_name_ja: string | null;
    station_name_en: string | null;
    station_coordinates: { lat: number; lng: number } | null;
    distance_m: number;
    walk_minutes: number;
    operator_qid: string | null;
    operator_name: string | null;
  };
  // Pre-computed top-5 other attractions within a 1.5 km haversine radius,
  // populated by scripts/inject_nearby_pois.py. Exposes a Solver-ingestible
  // walking-graph adjacency for itinerary composition.
  nearby_pois?: Array<{
    qid: string;
    name_ja: string | null;
    name_en: string | null;
    coordinates: { lat: number; lng: number } | null;
    distance_m: number;
    walk_minutes: number;
    kinds: string[] | null;
  }>;
}

